hooks.command:
node -e "
const chunks = [];
process.stdin.on('data', c => chunks.push(c));
process.stdin.on('end', () => {
  try {
    const data = JSON.parse(Buffer.concat(chunks).toString());
    const entry = JSON.stringify({
      ts: new Date().toISOString(),
      event: 'PostToolUse',
      agent_id: data.agent_id || null,
      agent_type: data.agent_type || null,
      session_id: data.session_id || null,
      tool: data.tool_name || null,
      input: data.tool_input || null,
      response_summary: typeof data.tool_response === 'string'
        ? data.tool_response.slice(0, 300)
        : JSON.stringify(data.tool_response || '').slice(0, 300)
    });
    const fs = require('fs');
    fs.mkdirSync('.claude/spy', { recursive: true });
    fs.appendFileSync('.claude/spy/activity.jsonl', entry + '\n');
  } catch(e) {}
});
"

